301	    int cnt = 0; Vertex V, W;
302	    for (each vertex V)
303	        if (indegree[V] == 0) Enqueue(Q, V);
304	    while (!IsEmpty(Q)) {
305	        V = Dequeue(Q); 
306	        TopNum[V] = ++cnt;
307	        for (each W adjacent to V)
308	            if (--indegree[W] == 0) Enqueue(Q, W);
309	    }
310	    if (cnt != NumVertex) Error("Graph has a cycle");
311	    free(Q);
312	}
